-- Catálogo Zorro/Exprezo — 2573 productos — motor: mariadb
-- Empareja por codigo_barras (EAN). Omitidos sin EAN: 0

SET NAMES utf8mb4;

CREATE TABLE IF NOT EXISTS productos (
  codigo_barras   VARCHAR(32) PRIMARY KEY,
  id_zorro        VARCHAR(32),
  nombre          VARCHAR(255),
  marca           VARCHAR(120),
  categoria       VARCHAR(120),
  departamento    VARCHAR(120),
  unidad          VARCHAR(20),
  precio          DECIMAL(10,2),
  precio_descuento DECIMAL(10,2),
  precio_caja     DECIMAL(10,2),
  piezas_caja     INT,
  stock           INT,
  actualizado     TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

